import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import API from '../../services/api';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const { data } = await API.post('/auth/login', { email, password });
      login(data);
      data.role === 'volunteer' ? navigate('/dashboard') : navigate('/report-home');
    } catch (err) {
      alert("Invalid credentials");
    }
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-[80vh]">
      <form onSubmit={handleSubmit} className="bg-white p-8 rounded-3xl shadow-lg w-full max-w-md">
        <h2 className="text-2xl font-bold mb-6 text-center">Login to FoodBridge</h2>
        <input type="email" placeholder="Email" className="w-full mb-4 p-4 border rounded-2xl" onChange={e => setEmail(e.target.value)} />
        <input type="password" placeholder="Password" className="w-full mb-6 p-4 border rounded-2xl" onChange={e => setPassword(e.target.value)} />
        <button className="w-full bg-green-600 text-white py-4 rounded-2xl font-bold">Login</button>
        <p className="mt-4 text-center">New? <Link to="/register" className="text-green-600">Create account</Link></p>
      </form>
    </div>
  );
}
